import React, { useState, useEffect } from 'react';
import CalendarComponent from '../components/CalendarComponent';
import DayPlanner from '../components/DayPlanner';
import { apiFetch } from '../api';
import './css/Calendar.css';

function CalendarPage({ user }) {
  const daysOfWeek = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState('Sunday');
  const [selectedWeek, setSelectedWeek] = useState('');
  const [dayRecipes, setDayRecipes] = useState([]);

  useEffect(() => {
    const fetchDayMeals = async () => {
      try {
        const formattedDate = new Date(selectedDate).toISOString().split('T')[0];
        const response = await apiFetch(
          `/mealPlans/${formattedDate}/${user.id || user._id}`
        );
        if (response.ok) {
          const mealPlans = await response.json();
          const recipePromises = mealPlans.map((meal) =>
            apiFetch(`/recipes/${meal.recipe_id}`).then((r) => r.json())
          );
          setDayRecipes(await Promise.all(recipePromises));
        } else {
          setDayRecipes([]);
        }
      } catch (error) {
        console.error('Error fetching day meals:', error);
      }
    };
    if (selectedDate && user) fetchDayMeals();
  }, [selectedDate, user]);

  const handleDateChange = (date) => {
    setSelectedDate(date);
    setSelectedDay(daysOfWeek[new Date(date).getDay()]);
    const startOfWeek = new Date(date);
    startOfWeek.setDate(date.getDate() - date.getDay());
    const endOfWeek = new Date(startOfWeek);
    endOfWeek.setDate(startOfWeek.getDate() + 6);
    setSelectedWeek(
      `${startOfWeek.getMonth() + 1}/${startOfWeek.getDate()}-${endOfWeek.getMonth() + 1}/${endOfWeek.getDate()}`
    );
  };

  return (
    <div className="calendar-page">
      <h1>Planner</h1>
      <div className="calendar-layout">
        <CalendarComponent selectedDate={selectedDate} handleDateChange={handleDateChange} />
        <DayPlanner
          user={user}
          recipes={dayRecipes}
          selectedDay={selectedDay}
          setSelectedDay={setSelectedDay}
          selectedWeek={selectedWeek}
          selectedDate={selectedDate}
          setSelectedDate={setSelectedDate}
        />
      </div>
    </div>
  );
}

export default CalendarPage;
